import { isArray } from '../../utils/zcutils';
import { d3_merge } from '../../core/d3-constants';
import { isFunction } from '../../utils/function-utils';

/**
 * @param  {Array} array
 * @param  {[Array | Number | String]} keys
 * @return {Array}
 */
function getDataByKeys(array, keys) {
    if (!isArray(keys)) {
        keys = [keys];
    }

    var readData = key => getDataByKey(array, key);
    return d3_merge(keys.map(readData));
}

/**
 * @param  {Array} array
 * @param  {[Number | String]} key
 * @return {Array}
 */
function getDataByKey(array, key) {
    var output = [];

    if (array && isArray(array) && array.every(_ => isArray(_))) {
        //Hierarchy array
        array.forEach(_ => collectRecursively(_, key, output));
    } else {
        collectData.call(null, array, key, output);
    }

    return output;
}

function collectData(data, key, output) {
    var value = isFunction(key) ? key(data) : data[key];

    if (isArray(value)) {
        output.push(...value);
    } else {
        output.push(value);
    }
}

function collectRecursively(subArray, key, output) {
    var subOutput = getDataByKey(subArray, key);
    output.push(...subOutput);
}

export { getDataByKeys };
